+func isUnsafeProjectRelativePath(cleanPath string) bool {
+	if cleanPath == "" {
+		return false
+	}
+	if filepath.IsAbs(cleanPath) {
+		return true
+	}
+	parentPrefix := ".." + string(filepath.Separator)
+	return cleanPath == ".." || strings.HasPrefix(cleanPath, parentPrefix)
+}
